1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Customer = { yearsWithMHPCO: number };
20	type Scenario = { customer: Customer; steps: QuoteStep[] };
21	
22	const BLOCK_SIZE = 3;
23	const BLOCK_PREMIUM = 60;
24	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
25	
26	const CURSED_RATE = 0.5;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const HIGH_ENCHANTMENT_RATE = 0.3;
29	
30	const isCursed = (item: Item): boolean => item.cursed === true;
31	const isHighlyEnchanted = (item: Item): boolean =>
32	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
33	
34	const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
35	  { applies: isCursed, rate: CURSED_RATE },
36	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
37	];
38	
39	const groupByType = (items: Item[]): Map<string, Item[]> => {
40	  const groups = new Map<string, Item[]>();
41	  for (const item of items) {
42	    const group = groups.get(item.type) ?? [];
43	    group.push(item);
44	    groups.set(item.type, group);
45	  }
46	  return groups;
47	};
48	
49	const basePremiumFor = (type: string) => BASE_PREMIUM[type];
50	
51	const premiumForGroup = (type: string, group: Item[]) => {
52	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
53	    return BLOCK_PREMIUM;
54	  }
55	  return group.length * basePremiumFor(type);
56	};
57	
58	const itemSurcharges = (item: Item) => {
59	  const base = basePremiumFor(item.type);
60	  return SURCHARGE_RULES
61	    .filter((rule) => rule.applies(item))
62	    .reduce((sum, rule) => sum + base * rule.rate, 0);
63	};
64	
65	const policyBasePremium = (items: Item[]) =>
66	  [...groupByType(items)].reduce(
67	    (total, [type, group]) => total + premiumForGroup(type, group),
68	    0,
69	  );
70	
71	const sumItemSurcharges = (items: Item[]) =>
72	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
73	
74	const FIRST_INSURANCE_RATE = 0.1;
75	const LOYALTY_THRESHOLD_YEARS = 2;
76	const LOYALTY_RATE = 0.2;
77	const FOLLOWUP_RATE = 0.15;
78	
79	type QuoteContext = { customer: Customer; stepIndex: number };
80	
81	type PolicyAdjustment = {
82	  applies: (ctx: QuoteContext) => boolean;
83	  signedRate: number;
84	};
85	
86	const POLICY_ADJUSTMENTS: PolicyAdjustment[] = [
87	  { applies: () => true, signedRate: +FIRST_INSURANCE_RATE },
88	  {
89	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS,
90	    signedRate: -LOYALTY_RATE,
91	  },
92	  { applies: ({ stepIndex }) => stepIndex > 0, signedRate: -FOLLOWUP_RATE },
93	];
94	
95	const policyAdjustment = (ctx: QuoteContext, policyBase: number) =>
96	  POLICY_ADJUSTMENTS
97	    .filter((rule) => rule.applies(ctx))
98	    .reduce((sum, rule) => sum + policyBase * rule.signedRate, 0);
99	
100	const quote = (step: QuoteStep, customer: Customer, stepIndex: number) => {
101	  const policyBase = policyBasePremium(step.items);
102	  const premium =
103	    policyBase +
104	    policyAdjustment({ customer, stepIndex }, policyBase) +
105	    sumItemSurcharges(step.items);
106	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
107	};
108	
109	export const run = (input: Scenario): unknown => ({
110	  results: input.steps.map((step, i) => quote(step, input.customer, i)),
111	});
